INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('bef940e0-3ffe-4993-91d2-4ec268071374', 'LTS_Q2_2025_MOV_001', 'Kể câu chuyện theo hình', '{"images": ["questions/story-images/images/1773910771732_19d837ac_q2_speaking_mov_p2_1.png", "questions/story-images/images/1773910777039_0459e6e4_q2_speaking_mov_p2_2.png", "questions/story-images/images/1773910784408_c29d9344_q2_speaking_mov_p2_3.png", "questions/story-images/images/1773910789685_a06c7961_q2_speaking_mov_p2_4.png"], "audioUrl": "listen-and-speak/audio/1773910948079_4a11aac6_mov-speaking-2.mp3", "isBackup": false}', '{"expectedAnswers": ["First, Vicky, Harry and their mom are in the living room. Vicky is colouring the picture, Harry is playing with his toy car, and their mom is sitting next to Vicky, watching her daughter doing her work.", "Then, Harry looks at the tree outside the living from, and point at a cat trying to hold tight on a branch of the tree.", "The mother run outside, climb up the tree with the ladder and bring the cat down while the children are watching her.", "The three members of the family warmly welcome the cat to their house, and happily play with it."]}', 'LISTEN_AND_SPEAK_WITH_STORY_IMAGES', 'medium', null, 1.00, null, null, '');
